		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) (err error) {
			ctx := cmd.Context()
			cfg := flags.spannerConfig()

			if err := requireDatabaseConfig(cfg); err != nil {
				return err
