					err = cerr
				}
			}()

			if err := client.DropDatabase(ctx); err != nil {
				return err
			}

			if _, err := fmt.Fprintf(cmd.OutOrStdout(), "Dropped database: %s\n", cfg.DatabasePath()); err != nil {
				return err
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&force, "force", false, "confirm irreversible database drop")

