func normalizeSQL(sql string) string {
	var b strings.Builder
	inString := false
	var quote rune
	spacePending := false

	runes := []rune(strings.TrimSpace(sql))
	for i := 0; i < len(runes); i++ {
		r := runes[i]
		if inString {
			b.WriteRune(r)
			if r == '\\' && i+1 < len(runes) {
				i++
				b.WriteRune(runes[i])
				continue
			}
			if r == quote {
				if i+1 < len(runes) && runes[i+1] == quote && quote != rune(0x60) {
					i++
					b.WriteRune(runes[i])
					continue
				}
				inString = false
			}
			continue
		}

		switch r {
		case '\'', '"', rune(0x60):
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			inString = true
			quote = r
			b.WriteRune(r)
		case ' ', '\t', '\n', '\r':
			spacePending = b.Len() > 0
		default:
			if spacePending && b.Len() > 0 {
				b.WriteByte(' ')
				spacePending = false
			}
			b.WriteRune(r)
		}
	}

	return b.String()
}

func normalizeConstraintSQL(sql string) string {
	sql = strings.ReplaceAll(sql, "ON DELETE NO ACTION", "")
	return normalizeSQL(sql)
}

func normalizeOnDelete(onDelete string) string {
	if onDelete == "" {
		return "NO ACTION"
	}
	return onDelete
}
func (g *Generator) formatGoSource(filename string, src []byte) ([]byte, error) {
	modulePath, langVersion := detectGoModuleConfig(g.opts.OutDir)
	generatedFile := filepath.Join(g.opts.OutDir, filename)
	if absPath, err := filepath.Abs(generatedFile); err == nil {
		generatedFile = absPath
	}

	importsProcessMu.Lock()
	previousLocalPrefix := imports.LocalPrefix
	imports.LocalPrefix = modulePath
	defer func() {
		imports.LocalPrefix = previousLocalPrefix
		importsProcessMu.Unlock()
	}()
	formatted, err := imports.Process(generatedFile, src, &imports.Options{
		TabWidth:  8,
		TabIndent: true,
		Comments:  true,
		Fragment:  true,
	})
	if err != nil {
		return nil, fmt.Errorf("goimports: %w", err)
	}

	formatted, err = gofumpt.Source(formatted, gofumpt.Options{
		LangVersion: langVersion,
		ModulePath:  modulePath,
		ExtraRules:  true,
	})
	if err != nil {
		return nil, fmt.Errorf("gofumpt: %w", err)
	}

	return formatted, nil
}

